import React from 'react';

const Footer = () => {
    const currentYear = new Date().getFullYear();

    return (
        <footer id="footer" className="footer position-relative">
            <div className="container">
                <h3 className="text-gradient fw-bold mb-3">Deepak Aruldoss</h3>
                <p className="text-muted mb-4 small">Connect with me on social media.</p>
                <div className="social-links d-flex justify-content-center mb-4">
                    <a href="https://www.facebook.com/share/18az6SS6kn/" target="_blank" rel="noreferrer" className="glass-effect"><i className="bi bi-facebook"></i></a>
                    <a href="https://www.instagram.com/deepakarul55?igsh=YXFwMXhwczFhY2pl" target="_blank" rel="noreferrer" className="glass-effect"><i className="bi bi-instagram"></i></a>
                    <a href="https://www.linkedin.com/in/deepak-aruldoss-40426b218?utm_source=share&utm_campaign=share_via&utm_content=profile" target="_blank" rel="noreferrer" className="glass-effect"><i className="bi bi-linkedin"></i></a>
                </div>
                <div className="copyright text-muted small border-top border-secondary pt-4">
                    <span>&copy; {currentYear}</span> <strong className="px-1 text-white">Deepak Aruldoss</strong> <span>All Rights Reserved</span>
                </div>
            </div>
        </footer>
    );
};

export default Footer;
